import crypto from "node:crypto";
import { releaseStudioMonitor, tryClaimStudioMonitor, updateActiveStudioSession, } from "../activeStudioSession.js";
import { resolveAgentSessionKey } from "../agentSessionKey.js";
import { getConfig, hasCredentials, saveCredentials } from "../config.js";
import { StudioNavigationError } from "../errors.js";
import { applyFocusTarget, captureFocusTarget } from "../frontmostApp.js";
import { emitJson } from "../output.js";
import { resolveChannel } from "../studioChannel.js";
import { appendStudioEvent, eventLogPathForKey, readStudioEventLogTail, studioEventToLogLine, tailStudioEvents, } from "../studioEventLog.js";
import { isValidStudioRoute } from "../studioRoutes.js";
import { resolveStudioSessionTarget } from "../studioUrl.js";
// Convert a durable-log line back into an AgentEvent for a reader's onEvent. The
// line's `event` is the type with `studio:` stripped (but `tracePlan:` etc. keep
// their prefix), and the line itself carries the data fields.
function lineToAgentEvent(line) {
    const name = typeof line.event === "string" ? line.event : "";
    const type = name.includes(":") ? name : `studio:${name}`;
    return { id: "", type, data: line };
}
export { StudioNavigationError } from "../errors.js";
const WINDOW_CLOSE_GRACE_PERIOD_MS = 10_000;
const LOGIN_TIMEOUT_MS = 10 * 60 * 1000;
const UNREACHABLE_REASONS = new Set(["timeout", "push-failed", "window-closed"]);
function isUnreachable(reason) {
    return reason != null && UNREACHABLE_REASONS.has(reason);
}
export function handleStudioError(err) {
    if (err instanceof StudioNavigationError &&
        err.staleSessionId &&
        isUnreachable(err.reason)) {
        emitJson({ event: "not-responding", sessionId: err.staleSessionId });
    }
    else if (err instanceof StudioNavigationError) {
        emitJson({ event: "open-failed", reason: err.blockedReason ?? err.message });
    }
    else {
        emitJson({
            event: "open-failed",
            reason: err instanceof Error ? err.message : String(err),
        });
    }
    process.exit(1);
}
export function formatStudioUrlMessage(url) {
    return `Studio opened at: ${url}`;
}
export function emitWindowOpened(result, emit = emitJson) {
    if (result.opened && result.url) {
        emit({ event: "window-opened", url: result.url });
        console.error(formatStudioUrlMessage(result.url));
    }
}
function createEventSubscription(channel, sessionId, onEvent, restoreFocus) {
    let graceTimer = null;
    let endedNotified = false;
    const clearGraceTimer = () => {
        if (graceTimer) {
            clearTimeout(graceTimer);
            graceTimer = null;
        }
    };
    const notifyEnded = (baseEvent) => {
        if (!endedNotified) {
            endedNotified = true;
            restoreFocus();
            onEvent({ ...baseEvent, type: "studio:session-ended" });
        }
        clearGraceTimer();
        sub.abort();
    };
    const sub = channel.subscribe(sessionId, (event) => {
        if (event.type === "studio:window-closed") {
            clearGraceTimer();
            graceTimer = setTimeout(() => {
                graceTimer = null;
                updateActiveStudioSession({ windowState: "closed" });
                notifyEnded(event);
            }, WINDOW_CLOSE_GRACE_PERIOD_MS);
            return;
        }
        if (event.type === "studio:session-started") {
            if (graceTimer) {
                clearGraceTimer();
                console.error("Studio reconnected after page refresh");
            }
            return;
        }
        if (event.type === "studio:session-ended") {
            clearGraceTimer();
            notifyEnded(event);
            return;
        }
        if (event.type === "studio:session-closed") {
            return;
        }
        if (event.type === "studio:not-member") {
            restoreFocus();
            onEvent(event);
            sub.abort();
            return;
        }
        if (event.type === "studio:return-to-agent" ||
            event.type === "studio:edit-with-agent") {
            restoreFocus();
        }
        onEvent(event);
    }, (err) => {
        console.error(`studio event stream: ${err.message}`);
    });
    return {
        abort: () => {
            clearGraceTimer();
            sub.abort();
        },
        done: sub.done,
    };
}
export async function openStudioTo(path, opts = {}) {
    const config = getConfig();
    const serviceUrl = config.serviceUrl;
    const apiKey = !opts.forceLogin && hasCredentials() ? config.apiKey : null;
    const key = resolveAgentSessionKey();
    // Capture the terminal focus target once, in this terminal-child process. The
    // daemon (which outlives us under fire-and-forget) can't walk our process
    // tree, so we hand it the target and it restores focus on terminal events.
    const focusTarget = captureFocusTarget();
    const restoreFocus = () => applyFocusTarget(focusTarget);
    const channel = await resolveChannel(apiKey ?? "", serviceUrl);
    const finish = (sessionId, opened, resolvedApiKey, url) => {
        const persistent = channel.isPersistent();
        const base = {
            sessionId,
            serviceUrl,
            apiKey: resolvedApiKey,
            opened,
            persistent,
            url,
        };
        const wantsEvents = opts.tail || Boolean(opts.onEvent);
        // Daemon mode: the daemon is the sole poll + writer. A tail caller
        // fire-and-forgets (the daemon keeps the session, log, and focus alive); an
        // onEvent caller subscribes via the daemon. Neither runs its own poll.
        if (persistent) {
            if (!wantsEvents || opts.tail) {
                if (!opts.tail) {
                    restoreFocus();
                }
                return {
                    ...base,
                    abort: () => channel.destroy(),
                    done: Promise.resolve(),
                };
            }
            const subscription = createEventSubscription(channel, sessionId, opts.onEvent ?? (() => { }), restoreFocus);
            return { ...base, ...subscription };
        }
        // No daemon: elect a single writer so the fallback also has exactly one
        // backend poll. The writer polls, synthesizes terminals, restores focus, and
        // appends every event to the durable file; every other consumer reads the
        // file. The monitor lock (keyed by agent session) is the election.
        if (!wantsEvents) {
            restoreFocus();
            return {
                ...base,
                abort: () => channel.destroy(),
                done: Promise.resolve(),
            };
        }
        if (tryClaimStudioMonitor()) {
            // Writer: this process owns the poll. Mirror each agent-facing event
            // (including the synthesized session-ended) into the durable log so every
            // reader sees the same stream, and release the lock when it ends.
            const userOnEvent = opts.onEvent ?? (() => { });
            const sink = (event) => {
                appendStudioEvent(key, studioEventToLogLine(event, sessionId));
                userOnEvent(event);
            };
            const subscription = createEventSubscription(channel, sessionId, sink, restoreFocus);
            return {
                ...base,
                abort: subscription.abort,
                done: subscription.done.finally(() => releaseStudioMonitor()),
            };
        }
        // Reader: another process already owns the poll and is keeping the file
        // fresh. A tail caller just needs that to be true, so fire-and-forget; an
        // onEvent caller reads the writer's file until its own terminal event.
        if (opts.tail) {
            channel.destroy();
            return { ...base, abort: () => { }, done: Promise.resolve() };
        }
        const userOnEvent = opts.onEvent ?? (() => { });
        const abortController = new AbortController();
        const done = tailStudioEvents(key, (line) => userOnEvent(lineToAgentEvent(line)), {
            fromLine: readStudioEventLogTail(key).nextLine,
            abortSignal: abortController.signal,
        });
        return {
            ...base,
            abort: () => {
                abortController.abort();
                channel.destroy();
            },
            done,
        };
    };
    if (!apiKey) {
        const destination = opts.freshWindowPath ?? path;
        const destSeparator = destination.includes("?") ? "&" : "?";
        const buildSignInPath = (sid) => {
            const redirectPath = `${destination}${destSeparator}session=${encodeURIComponent(sid)}&pluginLogin=true`;
            return `/studio/sign-in?redirect_url=${encodeURIComponent(redirectPath)}&session=${encodeURIComponent(sid)}`;
        };
        const requestedSessionId = crypto.randomUUID();
        // The channel may reuse a live keyless window from an earlier login
        // invocation, in which case it returns that window's sessionId. Subscribe
        // to the returned id (not the one we minted) so the token, which lands on
        // the reused window's session, is actually observed.
        const openResult = await channel.openOrNavigate(buildSignInPath(requestedSessionId), {
            clientHeaders: opts.clientHeaders,
            sessionId: requestedSessionId,
            focusTarget: focusTarget ?? undefined,
        });
        const sessionId = openResult.sessionId;
        // Build the manual fallback URL from the *resolved* sessionId, not the
        // minted one: on a reused window they differ, and a sign-in link for a
        // session the plugin isn't polling would never complete the login. No-op
        // when the window was freshly opened (the two ids are equal).
        const signInUrl = `${serviceUrl}${buildSignInPath(sessionId)}`;
        if (openResult.opened) {
            opts.onWindowOpened?.(signInUrl);
        }
        opts.onLoginRequired?.(sessionId, signInUrl);
        const loginApiKey = await new Promise((resolve, reject) => {
            const timer = setTimeout(() => {
                sub.abort();
                reject(new Error("Login polling aborted"));
            }, LOGIN_TIMEOUT_MS);
            const keepalive = setInterval(() => process.stderr.write(""), 30_000);
            const cleanup = () => {
                clearTimeout(timer);
                clearInterval(keepalive);
            };
            const sub = channel.subscribe(sessionId, (event) => {
                if (event.type === "studio:authenticated" &&
                    typeof event.data?.token === "string") {
                    cleanup();
                    sub.abort();
                    resolve(event.data.token);
                }
            }, (err) => {
                cleanup();
                reject(err);
            });
        });
        saveCredentials(loginApiKey);
        // Mark the pointer authenticated so a later keyless login never reuses this
        // window: it auto-closes after sign-in (/studio/close), but the close is
        // unwitnessed (we abort the subscription on auth), so windowState stays
        // "open". Without this flip, the keyless reuse gate (!authenticated) would
        // re-attach a fresh login to the dead window and hang until timeout.
        updateActiveStudioSession({ authenticated: true });
        opts.onAuthenticated?.(sessionId);
        channel.setApiKey(loginApiKey);
        return finish(sessionId, openResult.opened, loginApiKey, openResult.opened ? signInUrl : undefined);
    }
    const { sessionId, opened } = await channel.openOrNavigate(path, {
        clientHeaders: opts.clientHeaders,
        focusTarget: focusTarget ?? undefined,
    });
    const url = opened
        ? resolveStudioSessionTarget({ serviceUrl, path, sessionId }).url
        : undefined;
    if (url) {
        opts.onWindowOpened?.(url);
    }
    return finish(sessionId, opened, apiKey, url);
}
export async function runOpenStudioTo(platform) {
    let path = process.argv.slice(2).find((a) => !a.startsWith("--"));
    if (!path) {
        console.error("Usage: openStudioTo <path>");
        process.exit(1);
    }
    if (!path.startsWith("/studio")) {
        path = "/studio";
    }
    if (!isValidStudioRoute(path)) {
        console.error(`Studio route not allowed: ${path}`);
        process.exit(1);
    }
    try {
        const result = await openStudioTo(path, {
            clientHeaders: {
                "x-bitfab-client-name": platform.cliBinary,
                "x-bitfab-client-display-name": platform.displayName,
            },
            tail: true,
            onLoginRequired: (sessionId, signInUrl) => {
                emitJson({ event: "auth-required", sessionId, signInUrl });
            },
            onWindowOpened: (url) => {
                emitWindowOpened({ opened: true, url });
            },
            onAuthenticated: (sessionId) => {
                emitJson({ event: "authenticated", sessionId });
            },
        });
        if (result.opened) {
            emitJson({ event: "started", sessionId: result.sessionId });
        }
        else {
            emitJson({ event: "navigated", sessionId: result.sessionId, path });
        }
        // Hand the agent the durable event stream. It attaches a Monitor to this
        // file and routes on the `event` field; it never keeps this process alive.
        emitJson({
            event: "monitor",
            sessionId: result.sessionId,
            eventFile: eventLogPathForKey(resolveAgentSessionKey()),
        });
        const shutdown = () => {
            result.abort();
            process.exit(0);
        };
        process.on("SIGINT", shutdown);
        process.on("SIGTERM", shutdown);
        // Daemon path: `done` is already resolved, so we exit immediately
        // (fire-and-forget) while the daemon keeps the session and stream alive.
        // Direct path: `done` resolves only at the terminal event, keeping this
        // process alive to write the durable log until then.
        await result.done;
        result.abort();
        process.exit(0);
    }
    catch (err) {
        if (err instanceof StudioNavigationError &&
            err.staleSessionId &&
            isUnreachable(err.reason)) {
            emitJson({
                event: "not-responding",
                sessionId: err.staleSessionId,
                path,
            });
        }
        else if (err instanceof StudioNavigationError) {
            emitJson({
                event: "open-failed",
                sessionId: "none",
                reason: err.blockedReason ?? err.message,
            });
        }
        else {
            emitJson({
                event: "open-failed",
                sessionId: "none",
                reason: err.message,
            });
        }
        process.exit(1);
    }
}
